#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
INNOVA - Generador de lista para etiquetado
============================================
Lee una carpeta de disenos procesados (JPG/PNG) cuyo nombre sigue el formato:
    COD001 - Cliente - 290x200 - Observacion.jpg
y genera en la carpeta hermana "etiquetados/" tres archivos:

  1. lista_etiquetado_<cierre>.json   -> para importar en INNOVA_Etiquetado.html
  2. tabla_<cierre>.pdf               -> lista de chequeo imprimible con miniaturas
  3. etiquetas_<cierre>.pdf           -> paginas 50x50mm listas para la DT01 (WePrint)

Estructura esperada:
  /Fondos semana/
    originales/     <- JPGs originales (gestionado por el cortador)
    cortados/       <- entrada de este script
    etiquetados/    <- salida de este script (se crea automaticamente)

MODO AUTOMATICO: el cortador lo llama al terminar. No requiere accion manual.
MODO MANUAL: arrastrar la carpeta "cortados/" al .bat y presionar Enter.

USO por terminal:
    python generar_lista_etiquetado.py "C:\\ruta\\cortados"
    python generar_lista_etiquetado.py "C:\\ruta\\cortados" --cierre 2026-05-30
"""

import os, sys, re, json, base64, datetime, argparse
from io import BytesIO

# -- costura (opcional: si no se encuentra el script, se omite silenciosamente)
def _intentar_costura(carpeta, cierre, sin_pausa):
    try:
        script_dir = os.path.dirname(os.path.abspath(__file__))
        costura_py = os.path.join(script_dir, "..", "costura", "generar_costura.py")
        costura_py = os.path.normpath(costura_py)
        if not os.path.isfile(costura_py):
            print("[COSTURA] generar_costura.py no encontrado, se omite.")
            return
        import importlib.util
        spec   = importlib.util.spec_from_file_location("generar_costura", costura_py)
        modulo = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(modulo)
        modulo.generar_pdf_costura(carpeta, cierre=cierre, sin_pausa=sin_pausa)
    except Exception as e:
        print("[COSTURA] Error al generar lista de costura: %s" % e)

# ── dependencias ───────────────────────────────────────────────────────────
try:
    from PIL import Image
    Image.MAX_IMAGE_PIXELS = None   # fondos de gran formato superan el limite por defecto
except ImportError:
    print("\n[ERROR] Falta Pillow. Instalala con:  pip install Pillow\n")
    input("Enter para salir...")
    sys.exit(1)

try:
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.units import mm
    from reportlab.lib import colors
    from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
    from reportlab.lib.utils import ImageReader
    from reportlab.platypus import (
        SimpleDocTemplate, Table, TableStyle,
        Paragraph, Spacer, Image as RLImage, Flowable
    )
    from reportlab.pdfgen import canvas as rl_canvas
except ImportError:
    print("\n[ERROR] Falta ReportLab. Instalala con:  pip install reportlab\n")
    input("Enter para salir...")
    sys.exit(1)
# ──────────────────────────────────────────────────────────────────────────

IMG_EXT   = (".jpg", ".jpeg", ".png")
THUMB_MAX = 720
THUMB_Q   = 72

COD_RE = re.compile(r"cod[\s._\-]*0*(\d+)", re.IGNORECASE)
MED_RE = re.compile(r"(\d{2,4})\s*[x\u00d7]\s*(\d{2,4})", re.IGNORECASE)
SUF_RE = re.compile(
    r"\b(izq|der|sup|inf|izquierd[oa]|derech[oa]|superior|inferior|pa[\u00f1n]o\s*\d*)\b",
    re.IGNORECASE
)

# ── colores marca ─────────────────────────────────────────────────────────
ACCENT = colors.HexColor("#c2410c")
INK    = colors.HexColor("#0f0e0c")
PAPER  = colors.HexColor("#f6f1e8")
PAPER2 = colors.HexColor("#ede5d3")
RULE   = colors.HexColor("#d6cdb8")
MUTED  = colors.HexColor("#6b6357")

# ── assets embebidos ──────────────────────────────────────────────────────
LOGO_B64 = ""
QR_B64   = ""
LOGO_RATIO = 187 / 777   # alto / ancho del logo Innova

def _b64_to_pil(b64str):
    try:
        return Image.open(BytesIO(base64.b64decode(b64str)))
    except Exception:
        return None

def _pil_to_reader(pil_img):
    buf = BytesIO()
    pil_img.convert("RGB").save(buf, "PNG")
    buf.seek(0)
    return ImageReader(buf)
# ──────────────────────────────────────────────────────────────────────────


# ═══════════════════════════ PARSEO ═══════════════════════════════════════

def title_case(s):
    return re.sub(
        r"(^|[\s\-'\u2019.])([a-z\u00e1\u00e9\u00ed\u00f3\u00fa\u00fc\u00f1])",
        lambda m: m.group(1) + m.group(2).upper(), s.lower()
    )

def clean(s):
    s = re.sub(r"^[\s\-_\u2013\u00b7.|]+|[\s\-_\u2013\u00b7.|]+$", "", s)
    return re.sub(r"\s+", " ", s).strip()

def parse_name(filename):
    base = os.path.splitext(filename)[0]
    cod  = COD_RE.search(base)
    med  = MED_RE.search(base)
    if not cod and not med:
        return None
    if cod:
        codigo_num = int(cod.group(1))
        codigo = "Cod." + str(codigo_num).zfill(4)
    else:
        codigo_num = "_" + base.lower()
        codigo = "\u2014"
    medida = (med.group(1) + "x" + med.group(2)) if med else "\u2014"
    cliente, obs = "", ""
    if cod and med:
        after = base[cod.end():]
        m2 = MED_RE.search(after)
        cliente = after[:m2.start()]
        obs = after[m2.end():]
    elif cod:
        cliente = base[cod.end():]
    else:
        cliente = base[:med.start()]
        obs = base[med.end():]
    cliente = clean(cliente)
    cliente = title_case(cliente) if cliente else "(sin nombre)"
    obs = clean(SUF_RE.sub("", clean(obs)))
    if obs.lower() == "x":
        obs = ""
    return {"codigo": codigo, "codigoNum": codigo_num,
            "cliente": cliente, "medida": medida, "observacion": obs}


# ═══════════════════════════ MINIATURAS ═══════════════════════════════════

def make_thumb_b64(path):
    """Miniatura en base64 para el JSON."""
    try:
        im = Image.open(path).convert("RGB")
        im.thumbnail((THUMB_MAX, THUMB_MAX), Image.LANCZOS)
        buf = BytesIO()
        im.save(buf, format="JPEG", quality=THUMB_Q)
        return "data:image/jpeg;base64," + base64.b64encode(buf.getvalue()).decode()
    except Exception as e:
        print("   [aviso] miniatura JSON: %s" % e)
        return ""

def make_rl_thumb(path_or_b64, cell_mm=24):
    """Miniatura escalada como RLImage para insertar en tabla PDF."""
    try:
        if path_or_b64 and path_or_b64.startswith("data:"):
            _, b64 = path_or_b64.split(",", 1)
            im = Image.open(BytesIO(base64.b64decode(b64))).convert("RGB")
        else:
            im = Image.open(path_or_b64).convert("RGB")
        im.thumbnail((200, 200), Image.LANCZOS)
        iw, ih = im.size           # dimensiones reales del thumbnail generado
        buf = BytesIO()
        im.save(buf, "JPEG", quality=80)
        buf.seek(0)
        cell_pt = cell_mm * mm
        scale   = min(cell_pt / iw, cell_pt / ih)
        return RLImage(buf, width=iw * scale, height=ih * scale)
    except Exception as e:
        print("   [aviso] miniatura tabla: %s" % e)
        return None


# ═══════════════════════════ FLOWABLE CHECKBOX ════════════════════════════

class CheckBox(Flowable):
    """Cuadrado vacio para marcar a mano."""
    def __init__(self, size_pt=10):
        Flowable.__init__(self)
        self.size  = size_pt
        self.width = size_pt
        self.height= size_pt
    def draw(self):
        self.canv.setLineWidth(0.9)
        self.canv.setStrokeColor(MUTED)
        self.canv.rect(0, 0, self.size, self.size)


# ═══════════════════════ PDF TABLA ════════════════════════════════════════

def generar_pdf_tabla(designs, cierre, ruta_salida):
    """Tabla A4 con encabezado Innova, miniaturas y checkbox por diseno."""

    ss  = getSampleStyleSheet()
    slb = ParagraphStyle("lbl", fontName="Helvetica",      fontSize=7,  textColor=ACCENT, leading=9)
    sco = ParagraphStyle("cod", fontName="Helvetica-Bold", fontSize=9,  textColor=INK,   leading=11)
    scl = ParagraphStyle("cli", fontName="Helvetica-Bold", fontSize=10, textColor=INK,   leading=13)
    sme = ParagraphStyle("med", fontName="Helvetica",      fontSize=9,  textColor=MUTED, leading=11)
    sob = ParagraphStyle("obs", fontName="Helvetica",      fontSize=8,  textColor=ACCENT,leading=10)

    # anchos de columna (total ~178mm = A4 210 - 16 - 16)
    COL_W  = [28*mm, 24*mm, 60*mm, 26*mm, 26*mm, 14*mm]
    ROW_H  = 26 * mm
    HDR_H  = 8  * mm

    def hrow():
        return [[
            Paragraph("VISTA",   slb),
            Paragraph("CÓDIGO",  slb),
            Paragraph("CLIENTE", slb),
            Paragraph("MEDIDA",  slb),
            Paragraph("OBS.",    slb),
            Paragraph("✓",       slb),
        ]]

    data = hrow()
    rh   = [HDR_H]

    for d in designs:
        src   = d.get("_path") or d.get("img", "")
        thumb = make_rl_thumb(src, 24) if src else None
        obs   = d.get("observacion") or ""
        data.append([
            thumb or "",
            Paragraph(d["codigo"],  sco),
            Paragraph(d["cliente"], scl),
            Paragraph(d["medida"],  sme),
            Paragraph(obs,          sob),
            CheckBox(size_pt=9),
        ])
        rh.append(ROW_H)

    tabla = Table(data, colWidths=COL_W, rowHeights=rh)
    tabla.setStyle(TableStyle([
        ("BACKGROUND",    (0,0), (-1,0),  PAPER2),
        ("LINEBELOW",     (0,0), (-1,0),  1.0, INK),
        ("TOPPADDING",    (0,0), (-1,0),  4),
        ("BOTTOMPADDING", (0,0), (-1,0),  4),
        ("ROWBACKGROUNDS",(0,1), (-1,-1), [colors.white, PAPER]),
        ("LINEBELOW",     (0,1), (-1,-1), 0.4, RULE),
        ("VALIGN",        (0,0), (-1,-1), "MIDDLE"),
        ("ALIGN",         (0,0), (-1,-1), "LEFT"),
        ("ALIGN",         (0,1), (0,-1),  "CENTER"),
        ("ALIGN",         (-1,0),(-1,-1), "CENTER"),
        ("TOPPADDING",    (0,1), (-1,-1), 3),
        ("BOTTOMPADDING", (0,1), (-1,-1), 3),
        ("LEFTPADDING",   (0,0), (-1,-1), 5),
        ("RIGHTPADDING",  (0,0), (-1,-1), 5),
        ("BOX",           (0,0), (-1,-1), 0.8, RULE),
    ]))

    logo_obj = _b64_to_pil(LOGO_B64)
    logo_rdr = _pil_to_reader(logo_obj) if logo_obj else None

    def on_page(canv, doc):
        canv.saveState()
        PW, PH = A4
        canv.setStrokeColor(RULE); canv.setLineWidth(0.5)
        canv.line(16*mm, PH-11*mm, PW-16*mm, PH-11*mm)
        if logo_rdr:
            lw = 28*mm; lh = lw * LOGO_RATIO
            canv.drawImage(logo_rdr, 16*mm, PH-10*mm,
                           width=lw, height=lh, preserveAspectRatio=True, anchor="sw")
        canv.setFont("Helvetica-Bold", 9); canv.setFillColor(INK)
        canv.drawString(52*mm, PH-7.5*mm, "Lista de etiquetado")
        canv.setFont("Helvetica", 8); canv.setFillColor(MUTED)
        canv.drawString(52*mm, PH-11.5*mm, "Cierre: " + cierre)
        canv.setFont("Helvetica", 7.5)
        canv.drawRightString(PW-16*mm, PH-9.5*mm, "Pag. %d" % doc.page)
        canv.setStrokeColor(RULE)
        canv.line(16*mm, 10*mm, PW-16*mm, 10*mm)
        canv.setFont("Helvetica", 7); canv.setFillColor(MUTED)
        canv.drawString(16*mm, 7*mm, "INNOVA \u00b7 Fondos fotogr\u00e1ficos")
        canv.drawRightString(PW-16*mm, 7*mm, "innova54.com")
        canv.restoreState()

    doc = SimpleDocTemplate(
        ruta_salida, pagesize=A4,
        leftMargin=16*mm, rightMargin=16*mm,
        topMargin=15*mm, bottomMargin=14*mm,
        title="INNOVA - Lista de etiquetado - " + cierre,
    )
    doc.build([Spacer(1, 6*mm), tabla],
              onFirstPage=on_page, onLaterPages=on_page)
    print("  [PDF tabla]     %s" % ruta_salida)


# ═══════════════════════ PDF ETIQUETAS 50x50mm ════════════════════════════

def generar_pdf_etiquetas(designs, cierre, ruta_salida):
    """Una pagina 50x50mm por diseno original, lista para WePrint DT01."""
    PW = PH = 50 * mm

    logo_obj = _b64_to_pil(LOGO_B64)
    qr_obj   = _b64_to_pil(QR_B64)
    logo_rdr = _pil_to_reader(logo_obj) if logo_obj else None
    qr_rdr   = _pil_to_reader(qr_obj)   if qr_obj   else None

    canv = rl_canvas.Canvas(ruta_salida, pagesize=(PW, PH))

    def fit_text(c, text, max_w, start_pt, min_pt=6):
        pt = start_pt
        c.setFontSize(pt)
        while c.stringWidth(text) > max_w and pt > min_pt:
            pt -= 0.4
            c.setFontSize(pt)
        return pt

    for i, d in enumerate(designs):
        if i > 0:
            canv.showPage()
        nombre = d["cliente"]

        # logo
        lw = 34*mm; lh = lw * LOGO_RATIO
        if logo_rdr:
            canv.drawImage(logo_rdr, (PW-lw)/2, PH-2.4*mm-lh,
                           width=lw, height=lh, preserveAspectRatio=True)

        # separador punteado
        dot_y = PH - 2.4*mm - lh - 1.8*mm
        canv.setStrokeColor(colors.black)
        canv.setLineWidth(0.4)
        canv.setDash(0.7, 0.9)
        canv.line(6*mm, dot_y, 44*mm, dot_y)
        canv.setDash()

        # nombre cliente
        canv.setFillColor(colors.black)
        name_y = dot_y - 4.8*mm
        pt = fit_text(canv, nombre, 43*mm, start_pt=11, min_pt=7)
        canv.setFont("Helvetica", pt)
        canv.drawCentredString(PW/2, name_y, nombre)

        # gracias
        gracias_y = name_y - 4.4*mm
        canv.setFont("Helvetica", 9.5)
        canv.drawCentredString(PW/2, gracias_y, "\u00a1Gracias por elegirnos!")

        # QR
        q = 20.5*mm
        qx = (PW - q) / 2
        qy = gracias_y - 1.6*mm - q
        if qr_rdr:
            canv.drawImage(qr_rdr, qx, qy, width=q, height=q)

        # pie
        canv.setFont("Helvetica", 6.6)
        canv.drawCentredString(PW/2, qy-2.8*mm,  "Tu opini\u00f3n cuenta. Contanos tu")
        canv.drawCentredString(PW/2, qy-5.5*mm,  "experiencia en Google")

    canv.save()
    print("  [PDF etiquetas] %s" % ruta_salida)


# ═══════════════════════════ MAIN ═════════════════════════════════════════

def main():
    ap = argparse.ArgumentParser()
    ap.add_argument("carpeta", nargs="?", help="Carpeta cortados/ con los disenos procesados")
    ap.add_argument("--cierre", default=datetime.date.today().isoformat())
    ap.add_argument("--sin-pausa", action="store_true",
                    help="Suprime el 'Enter para salir' final (uso interno del cortador)")
    args = ap.parse_args()

    sin_pausa = args.sin_pausa

    carpeta = args.carpeta
    if not carpeta:
        carpeta = input(
            "Arrastra la carpeta 'cortados' y presiona Enter:\n> "
        ).strip().strip('"')
    if not carpeta or not os.path.isdir(carpeta):
        print("\n[ERROR] Carpeta no valida:", carpeta)
        if not sin_pausa:
            input("Enter para salir...")
        return

    carpeta = os.path.abspath(carpeta)

    # Carpeta de salida: hermana de la carpeta de entrada (un nivel arriba)
    carpeta_raiz      = os.path.dirname(carpeta)
    carpeta_etiquetados = os.path.join(carpeta_raiz, "etiquetados")
    os.makedirs(carpeta_etiquetados, exist_ok=True)

    archivos = [f for f in sorted(os.listdir(carpeta)) if f.lower().endswith(IMG_EXT)]
    print("\nProcesando %d archivo(s) en: %s\n" % (len(archivos), carpeta))

    designs, seen, no_reconocidos = [], set(), []
    for f in archivos:
        p = parse_name(f)
        if not p:
            no_reconocidos.append(f)
            print("  [omitido] sin codigo/medida: %s" % f)
            continue
        key = str(p["codigoNum"])
        if key in seen:
            continue
        seen.add(key)
        ruta_img = os.path.join(carpeta, f)
        p["_path"] = ruta_img
        p["img"]   = make_thumb_b64(ruta_img)
        print("  [ok] %s  -  %s  -  %s%s" % (
            p["codigo"], p["cliente"], p["medida"],
            ("  (" + p["observacion"] + ")") if p["observacion"] else ""
        ))
        designs.append(p)

    designs.sort(key=lambda d: d["codigoNum"] if isinstance(d["codigoNum"], int) else 9999)

    safe = re.sub(r"[^\w\-]+", "-", args.cierre)

    # JSON (sin _path, va a etiquetados/)
    paquete = {
        "innova_etiquetado": 2,
        "cierre": args.cierre,
        "generado": datetime.datetime.now().isoformat(timespec="seconds"),
        "designs": [{k: v for k, v in d.items() if k != "_path"} for d in designs],
        "estados": {}
    }
    ruta_json = os.path.join(carpeta_etiquetados, "lista_etiquetado_%s.json" % safe)
    with open(ruta_json, "w", encoding="utf-8") as fh:
        json.dump(paquete, fh, ensure_ascii=False)
    print("  [JSON]          %s" % ruta_json)

    # PDFs (van a etiquetados/)
    if designs:
        generar_pdf_tabla(designs, args.cierre,
                          os.path.join(carpeta_etiquetados, "tabla_%s.pdf" % safe))
        generar_pdf_etiquetas(designs, args.cierre,
                              os.path.join(carpeta_etiquetados, "etiquetas_%s.pdf" % safe))

    # -- generar lista de costura automáticamente ---------------------------
    _intentar_costura(carpeta, args.cierre, sin_pausa)

    print("\n" + "=" * 54)
    print(" ETIQUETADO: %d diseno(s)" % len(designs))
    if no_reconocidos:
        print(" Sin reconocer: %d (revisar nombre)" % len(no_reconocidos))
    print("")
    print("  Carpeta: %s" % carpeta_etiquetados)
    print("  JSON     -> lista_etiquetado_%s.json" % safe)
    if designs:
        print("  TABLA    -> tabla_%s.pdf" % safe)
        print("  ETIQUETAS-> etiquetas_%s.pdf" % safe)
    print("")
    print(" Subi el .json a Google Drive para el dia del etiquetado.")
    print("=" * 54 + "\n")

    if not sin_pausa:
        input("Listo. Enter para salir...")


if __name__ == "__main__":
    main()
